import { ChangeDetectionStrategy, Component, inject, signal } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { Router, RouterLink } from '@angular/router';
import { AuthService } from '../core/auth.service';
import { errorMessage } from '../core/api.service';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [FormsModule, RouterLink],
  templateUrl: './login.component.html',
  styleUrl: './auth.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class LoginComponent {
  private readonly auth = inject(AuthService);
  private readonly router = inject(Router);

  email = signal('');
  password = signal('');
  error = signal<string | null>(null);
  loading = signal(false);

  submit(): void {
    this.error.set(null);
    if (!this.email().includes('@') || this.password().length < 4) {
      this.error.set('Enter a valid email and a password of at least 4 characters.');
      return;
    }
    this.loading.set(true);
    this.auth
      .login(this.email(), this.password())
      .then(() => this.router.navigate(['/dashboard']))
      .catch((err) =>
        this.error.set(errorMessage(err, 'Invalid email or password.')),
      )
      .finally(() => this.loading.set(false));
  }

  demo(): void {
    this.error.set(null);
    this.loading.set(true);
    this.auth
      .demoLogin()
      .catch((err) =>
        this.error.set(errorMessage(err, 'Demo sign-in is unavailable.')),
      )
      .finally(() => this.loading.set(false));
  }
}
